from basic_agent import BasicAgent

class EchoAgent(BasicAgent):
    def __init__(self):
        self.name = "EchoAgent"
        self.metadata = {
            "name": self.name,
            "description": "Echo back the provided text.",
            "parameters": {"type": "object", "properties": {"text": {"type": "string"}}, "required": ["text"]},
        }
        super().__init__()

    def perform(self, text="", **kwargs):
        return f"Echo: {text}"

import ast, operator
from basic_agent import BasicAgent

_OPS = {ast.Add: operator.add, ast.Sub: operator.sub, ast.Mult: operator.mul, ast.Div: operator.truediv}

def _ev(node):
    if isinstance(node, ast.Constant):
        return node.value
    if isinstance(node, ast.BinOp):
        return _OPS[type(node.op)](_ev(node.left), _ev(node.right))
    raise ValueError("unsupported")

class CalculatorAgent(BasicAgent):
    def __init__(self):
        self.name = "CalculatorAgent"
        self.metadata = {"name": self.name, "description": "Evaluate arithmetic.", "parameters": {"type": "object", "properties": {"expression": {"type": "string"}}, "required": ["expression"]}}
        super().__init__()

    def perform(self, expression="", **kwargs):
        try:
            return str(_ev(ast.parse(expression, mode="eval").body))
        except Exception as e:
            return f"Error: {e}"
